    // C: t = luaH_new(L); sethvalue2s ...; api_incr_top;
    // C: if (narray > 0 || nrec > 0) luaH_resize(L, t, narray, nrec);
    let t = state.new_table();
    if narray > 0 || nrec > 0 {
        t.resize(state, narray as usize, nrec as usize)?;
