    // C: lua_pushstring(L, event); tt = lua_rawget(L, -2);
    state.push_bytes(event)?;
    let tt = state.raw_get(-2)?;
    if tt == LuaType::Nil {
        // C: lua_pop(L, 2); /* remove metatable and metafield */
        state.pop_n(2);
    } else {
        // C: lua_remove(L, -2); /* remove only metatable */
        state.remove(-2)?;
    }
    Ok(tt)
}

